import hmac
import hashlib

def create_signature(message: str, secret: str) -> str:
    return hmac.new(
        secret.encode(),
        message.encode(),
        hashlib.sha256
    ).hexdigest()

def verify_signature(message: str, secret: str, signature: str) -> bool:
    expected = create_signature(message, secret)
    return hmac.compare_digest(expected, signature)

secret = "my-secret-key"
msg = "important data"
sig = create_signature(msg, secret)
print(f"Signature: {sig}")
print(f"Verified: {verify_signature(msg, secret, sig)}")

