import signal
import time

class GracefulShutdown:
    def __init__(self):
        self.shutdown = False
        signal.signal(signal.SIGINT, self._handler)

    def _handler(self, signum, frame):
        print(f"\nSignal {signum} received, shutting down...")
        self.shutdown = True

    def run(self):
        while not self.shutdown:
            print("Working...")
            time.sleep(0.5)
        print("Cleanup complete")

