class AtomicCounter {
  #buffer = new SharedArrayBuffer(4);
  #view = new Int32Array(this.#buffer);

  constructor(initial = 0) {
    Atomics.store(this.#view, 0, initial);
  }

  increment() { return Atomics.add(this.#view, 0, 1); }
  decrement() { return Atomics.sub(this.#view, 0, 1); }
  get value() { return Atomics.load(this.#view, 0); }
  exchange(value) { return Atomics.exchange(this.#view, 0, value); }
  compareExchange(expected, replacement) {
    return Atomics.compareExchange(this.#view, 0, expected, replacement);
  }
}

