class PermissionChecker {
  constructor(userPermissions) {
    this.userPerms = new Set(userPermissions);
  }
  hasAll(required) { return required.isSubsetOf(this.userPerms); }
  hasAny(required) { return required.intersection(this.userPerms).size > 0; }
  missing(required) { return required.difference(this.userPerms); }
}

