import java.lang.invoke.*;

public class VarHandleDemo {
    private volatile int counter = 0;
    private static final VarHandle COUNTER;

    static {
        try {
            COUNTER = MethodHandles.lookup()
                .findVarHandle(VarHandleDemo.class, "counter", int.class);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    public void increment() {
        COUNTER.getAndAdd(this, 1);
    }

    public int getCounter() {
        return (int) COUNTER.getVolatile(this);
    }

    public static void main(String[] args) throws InterruptedException {
        VarHandleDemo demo = new VarHandleDemo();
        var threads = new Thread[10];
        for (int i = 0; i < 10; i++) {
            threads[i] = new Thread(() -> {
                for (int j = 0; j < 1000; j++) demo.increment();
            });
            threads[i].start();
        }
        for (var t : threads) t.join();
        System.out.println("Counter: " + demo.getCounter());
    }
}

import java.lang.invoke.*;

public class MethodHandlesDemo {
    static class Calculator {
        public int add(int a, int b) {
            return a + b;
        }

        private int multiply(int a, int b) {
            return a * b;
        }
    }

    public static void main(String[] args) throws Throwable {
        var lookup = MethodHandles.lookup();
        var calc = new Calculator();

        MethodHandle addHandle = lookup.findVirtual(
            Calculator.class, "add",
            MethodType.methodType(int.class, int.class, int.class)
        );

        int result = (int) addHandle.invoke(calc, 10, 20);
        System.out.println("Add: " + result);

        MethodHandle multHandle = lookup.findVirtual(
            Calculator.class, "multiply",
            MethodType.methodType(int.class, int.class, int.class)
        );
        multHandle = multHandle.bindTo(calc);
        System.out.println("Multiply: " + multHandle.invoke(5, 6));
    }
}

