var (
	queue []int
	cond  = sync.NewCond(&sync.Mutex{})
)

func producer() {
	for i := 0; i < 5; i++ {
		cond.L.Lock()
		queue = append(queue, i)
		fmt.Printf("Produced: %d\n", i)
		cond.Signal()
		cond.L.Unlock()
		time.Sleep(100 * time.Millisecond)
	}
}

func consumer(name string) {
	for {
		cond.L.Lock()
		for len(queue) == 0 {
			cond.Wait()
		}
		item := queue[0]
		queue = queue[1:]
		fmt.Printf("%s consumed: %d\n", name, item)
		cond.L.Unlock()
	}
}

func main() {
	go consumer("C1")
	go consumer("C2")
	producer()
	time.Sleep(100 * time.Millisecond)
}

