func producer(name string, count int) <-chan int {
	ch := make(chan int)
	go func() {
		for i := 0; i < count; i++ {
			ch <- i
		}
		close(ch)
	}()
	return ch
}

func fanIn(channels ...<-chan int) <-chan int {
	out := make(chan int)
	var wg sync.WaitGroup

	for _, ch := range channels {
		wg.Add(1)
		go func(c <-chan int) {
			defer wg.Done()
			for val := range c {
				out <- val
			}
		}(ch)
	}

	go func() {
		wg.Wait()
		close(out)
	}()
	return out
}

func main() {
	ch1 := producer("A", 3)
	ch2 := producer("B", 3)
	ch3 := producer("C", 3)

	merged := fanIn(ch1, ch2, ch3)

	for val := range merged {
		fmt.Println("Received:", val)
	}
}

