		result := n * n
		fmt.Printf("Worker %d: %d^2 = %d\n", id, n, result)
	}
}

func main() {
	nums := generator(1, 2, 3, 4, 5, 6)

	var wg sync.WaitGroup
	for i := 1; i <= 3; i++ {
		wg.Add(1)
		go square(nums, i, &wg)
	}

	wg.Wait()
	fmt.Println("All squared")
}

