type PubSub struct {
	mu       sync.RWMutex
	subscribers map[string]map[chan string]struct{}
}

func NewPubSub() *PubSub {
	return &PubSub{subscribers: make(map[string]map[chan string]struct{})}
}

func (ps *PubSub) Subscribe(topic string) chan string {
	ps.mu.Lock()
	defer ps.mu.Unlock()
	ch := make(chan string, 10)
	if ps.subscribers[topic] == nil {
		ps.subscribers[topic] = make(map[chan string]struct{})
	}
	ps.subscribers[topic][ch] = struct{}{}
	return ch
}

func (ps *PubSub) Publish(topic, message string) {
	ps.mu.RLock()
	defer ps.mu.RUnlock()
	for ch := range ps.subscribers[topic] {
		select {
		case ch <- message:
		default:
		}
	}
}

func main() {
	ps := NewPubSub()

	sub1 := ps.Subscribe("news")
	sub2 := ps.Subscribe("news")

	go func() {
		for msg := range sub1 {
			fmt.Println("Sub1 received:", msg)
		}
	}()

	go func() {
		for msg := range sub2 {
			fmt.Println("Sub2 received:", msg)
		}
	}()

	ps.Publish("news", "Hello subscribers!")
	ps.Publish("news", "Second message")
	fmt.Println("Messages published")
}

