type Event struct {
	Type string
	Data interface{}
}

type EventBus struct {
	mu       sync.RWMutex
	listeners map[string][]func(Event)
}

func NewEventBus() *EventBus {
	return &EventBus{listeners: make(map[string][]func(Event))}
}

func (eb *EventBus) On(eventType string, handler func(Event)) {
	eb.mu.Lock()
	defer eb.mu.Unlock()
	eb.listeners[eventType] = append(eb.listeners[eventType], handler)
}

func (eb *EventBus) Emit(event Event) {
	eb.mu.RLock()
	defer eb.mu.RUnlock()
	for _, handler := range eb.listeners[event.Type] {
		handler(event)
	}
}

func main() {
	bus := NewEventBus()

	bus.On("user.created", func(e Event) {
		fmt.Println("Email service:", e.Data)
	})
	bus.On("user.created", func(e Event) {
		fmt.Println("Log service: User created")
	})

	bus.Emit(Event{Type: "user.created", Data: "alice@example.com"})
	fmt.Println("Event emitted")
}

