import (
	"errors"
	"fmt"
	"sync/atomic"
	"time"
)

type State int32

const (
	Closed State = iota
	Open
	HalfOpen
)

type CircuitBreaker struct {
	state        atomic.Int32
	failureCount atomic.Int64
	threshold    int64
	timeout      time.Duration
	lastFailure  atomic.Int64
}

func NewCircuitBreaker(threshold int64, timeout time.Duration) *CircuitBreaker {
	return &CircuitBreaker{threshold: threshold, timeout: timeout}
}

func (cb *CircuitBreaker) Call(fn func() error) error {
	switch State(cb.state.Load()) {
	case Open:
		if time.Now().UnixNano()-cb.lastFailure.Load() > cb.timeout.Nanoseconds() {
			cb.state.Store(int32(HalfOpen))
		} else {
			return errors.New("circuit breaker open")
		}
	}

	err := fn()
	if err != nil {
		cb.failureCount.Add(1)
		cb.lastFailure.Store(time.Now().UnixNano())
		if cb.failureCount.Load() >= cb.threshold {
			cb.state.Store(int32(Open))
		}
		return err
	}

	cb.failureCount.Store(0)
	cb.state.Store(int32(Closed))
	return nil
}

func main() {
	cb := NewCircuitBreaker(3, 1*time.Second)

	for i := 0; i < 10; i++ {
		err := cb.Call(func() error {
			return errors.New("service error")
		})
		fmt.Printf("Call %d: %v\n", i+1, err)
		time.Sleep(200 * time.Millisecond)
	}
}

