import (
	"errors"
	"fmt"
	"math/rand"
	"time"
)

func retryWithBackoff(attempts int, fn func() error) error {
	for i := 0; i < attempts; i++ {
		err := fn()
		if err == nil {
			return nil
		}
		if i == attempts-1 {
			return fmt.Errorf("failed after %d attempts: %w", attempts, err)
		}
		backoff := time.Duration(100*(i+1)+rand.Intn(50)) * time.Millisecond
		fmt.Printf("Attempt %d failed, retrying in %v...\n", i+1, backoff)
		time.Sleep(backoff)
	}
	return nil
}

func main() {
	attempt := 0
	err := retryWithBackoff(3, func() error {
		attempt++
		if attempt < 3 {
			return errors.New("transient error")
		}
		return nil
	})

	if err != nil {
		fmt.Println("Failed:", err)
	} else {
		fmt.Println("Succeeded after", attempt, "attempts")
	}
}

