// MutationObserver ile DOM degisikliklerini izleme
class DomWatcher {
  constructor(options = {}) {
    this.observer = new MutationObserver((mutations) => {
      mutations.forEach(mutation => {
        if (mutation.type === 'childList') {
          mutation.addedNodes.forEach(node => {
            if (node.nodeType === 1) {
              this.onElementAdded(node);
            }
          });
          mutation.removedNodes.forEach(node => {
            if (node.nodeType === 1) {
              this.onElementRemoved(node);
            }
          });
        }

        if (mutation.type === 'attributes') {
          this.onAttributeChanged(
            mutation.target,
            mutation.attributeName,
            mutation.oldValue,
            mutation.target.getAttribute(mutation.attributeName)
          );
        }

        if (mutation.type === 'characterData') {
          this.onTextChanged(mutation.target, mutation.oldValue);
        }
      });
    });

    this.handlers = {
      elementAdded: [],
      elementRemoved: [],
      attributeChanged: [],
      textChanged: [],
    };
  }

  observe(target, config = {}) {
    this.observer.observe(target, {
      childList: true,
      attributes: true,
      characterData: true,
      subtree: true,
      attributeOldValue: true,
      characterDataOldValue: true,
      ...config
    });
  }

  onElementAdded(node) {
    this.handlers.elementAdded.forEach(h => h(node));
  }

  onElementRemoved(node) {
    this.handlers.elementRemoved.forEach(h => h(node));
  }

  onAttributeChanged(target, attr, oldVal, newVal) {
    this.handlers.attributeChanged.forEach(h => h(target, attr, oldVal, newVal));
  }

  onTextChanged(target, oldVal) {
    this.handlers.textChanged.forEach(h => h(target, oldVal));
  }

  on(event, handler) {
    if (this.handlers[event]) {
      this.handlers[event].push(handler);
    }
  }

  disconnect() {
    this.observer.disconnect();
  }
}

const watcher = new DomWatcher();
