watcher.on('elementAdded', (el) => console.log('Element added:', el));
watcher.on('attributeChanged', (el, attr, old, val) => console.log(`${attr}: ${old} -> ${val}`));

-- PostgreSQL trigger ile loglama
CREATE TABLE audit_log (
  id BIGSERIAL PRIMARY KEY,
  table_name TEXT NOT NULL,
  operation TEXT NOT NULL,
  old_data JSONB,
  new_data JSONB,
  changed_by TEXT DEFAULT current_user,
  changed_at TIMESTAMP DEFAULT NOW()
);

CREATE OR REPLACE FUNCTION audit_trigger_func()
RETURNS TRIGGER AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO audit_log(table_name, operation, new_data)
    VALUES (TG_TABLE_NAME, 'INSERT', row_to_json(NEW)::jsonb);
    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    INSERT INTO audit_log(table_name, operation, old_data, new_data)
    VALUES (TG_TABLE_NAME, 'UPDATE', row_to_json(OLD)::jsonb, row_to_json(NEW)::jsonb);
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO audit_log(table_name, operation, old_data)
    VALUES (TG_TABLE_NAME, 'DELETE', row_to_json(OLD)::jsonb);
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER users_audit_trigger
AFTER INSERT OR UPDATE OR DELETE ON users
FOR EACH ROW EXECUTE FUNCTION audit_trigger_func();

class CancellableFetch {
  constructor() {
    this.controllers = new Map();
  }

  async fetch(url, options = {}) {
    const controller = new AbortController();
    const id = Symbol(url);
    this.controllers.set(id, controller);

    try {
      const response = await fetch(url, {
        ...options,
        signal: controller.signal,
      });
      return await response.json();
    } finally {
      this.controllers.delete(id);
    }
  }

  cancel(url) {
    for (const [id, controller] of this.controllers) {
      controller.abort();
      this.controllers.delete(id);
    }
  }

  cancelOne(url) {
    for (const [id, controller] of this.controllers) {
      if (id.description === url) {
        controller.abort();
        this.controllers.delete(id);
        break;
      }
    }
  }
}

