// Performance API ile web vitals olcumu
class WebVitalsMonitor {
  constructor(options = {}) {
    this.endpoint = options.endpoint || '/api/vitals';
    this.sampleRate = options.sampleRate || 0.1;
  }

  init() {
    if (Math.random() > this.sampleRate) return;

    this.observeLCP();
    this.observeFID();
    this.observeCLS();
    this.observeTTFB();
    this.observeINP();
  }

  observeLCP() {
    new PerformanceObserver((list) => {
      const entries = list.getEntries();
      const lastEntry = entries[entries.length - 1];
      this.send('LCP', lastEntry.startTime);
    }).observe({ type: 'largest-contentful-paint', buffered: true });
  }

  observeFID() {
    new PerformanceObserver((list) => {
      list.getEntries().forEach(entry => {
        this.send('FID', entry.processingStart - entry.startTime);
      });
    }).observe({ type: 'first-input', buffered: true });
  }

  observeCLS() {
    let clsValue = 0;
    new PerformanceObserver((list) => {
      list.getEntries().forEach(entry => {
        if (!entry.hadRecentInput) {
          clsValue += entry.value;
        }
      });
      this.send('CLS', clsValue);
    }).observe({ type: 'layout-shift', buffered: true });
  }

  observeTTFB() {
    const navigation = performance.getEntriesByType('navigation')[0];
    if (navigation) {
      this.send('TTFB', navigation.responseStart - navigation.requestStart);
    }
  }

  observeINP() {
    new PerformanceObserver((list) => {
      list.getEntries().forEach(entry => {
        this.send('INP', entry.duration);
      });
    }).observe({ type: 'event', durationThreshold: 40, buffered: true });
  }

  async send(name, value) {
    try {
      const data = { name, value, url: location.href, timestamp: Date.now() };
      if (navigator.sendBeacon) {
        navigator.sendBeacon(this.endpoint, JSON.stringify(data));
      } else {
        await fetch(this.endpoint, {
          method: 'POST',
          body: JSON.stringify(data),
          keepalive: true
        });
      }
    } catch (e) {
      console.warn('Failed to send metric:', e);
    }
  }
}

new WebVitalsMonitor({ endpoint: '/analytics', sampleRate: 1.0 }).init();

class OfflineManager {
  constructor(cacheName = 'offline-v1') {
    this.cacheName = cacheName;
  }

  async init() {
    if ('caches' in window) {
      await this.createCache();
      window.addEventListener('online', () => this.syncPending());
      window.addEventListener('offline', () => this.showOfflineBanner());
    }
  }

  async createCache() {
    const cache = await caches.open(this.cacheName);
    const resources = [
      '/',
      '/index.html',
      '/styles.css',
      '/app.js',
      '/offline.html',
      '/images/logo.png'
    ];
    await cache.addAll(resources);
  }

  async cacheResource(url, response) {
    const cache = await caches.open(this.cacheName);
    cache.put(url, response.clone());
  }

  async getCached(url) {
    const cache = await caches.open(this.cacheName);
    const response = await cache.match(url);
    return response;
  }

  async savePendingRequest(request) {
    const db = await this.openDB();
    const tx = db.transaction('pending', 'readwrite');
    tx.objectStore('pending').add({
      url: request.url,
      method: request.method,
      headers: [...request.headers],
      body: await request.clone().text(),
      timestamp: Date.now()
    });
    await tx.done;
  }

  async syncPending() {
    const db = await this.openDB();
    const tx = db.transaction('pending', 'readonly');
    const requests = await tx.objectStore('pending').getAll();

    for (const req of requests) {
      try {
        await fetch(req.url, {
          method: req.method,
          headers: req.headers,
          body: req.body
        });
        const deleteTx = db.transaction('pending', 'readwrite');
        deleteTx.objectStore('pending').delete(req.timestamp);
        await deleteTx.done;
      } catch (e) {
        console.error('Sync failed:', e);
      }
    }
  }

  showOfflineBanner() {
    const banner = document.createElement('div');
    banner.className = 'offline-banner';
    banner.textContent = 'Internet baglantiniz kesildi. Uygulama cevrimdisi modda calisiyor.';
    document.body.prepend(banner);
  }

  async openDB() {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open('OfflineDB', 1);
      request.onupgradeneeded = (e) => {
        e.target.result.createObjectStore('pending', { keyPath: 'timestamp' });
      };
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }
}

