package main

import (
	"errors"
	"fmt"
)

type RingBuffer[T any] struct {
	data  []T
	size  int
	head  int
	tail  int
	count int
}

func NewRingBuffer[T any](size int) *RingBuffer[T] {
	return &RingBuffer[T]{
		data: make([]T, size),
		size: size,
	}
}

func (rb *RingBuffer[T]) Push(item T) error {
	if rb.count == rb.size {
		return errors.New("buffer full")
	}
	rb.data[rb.tail] = item
	rb.tail = (rb.tail + 1) % rb.size
	rb.count++
	return nil
}

func (rb *RingBuffer[T]) Pop() (T, error) {
	if rb.count == 0 {
		var zero T
		return zero, errors.New("buffer empty")
	}
	item := rb.data[rb.head]
	rb.head = (rb.head + 1) % rb.size
	rb.count--
	return item, nil
}

func (rb *RingBuffer[T]) Len() int { return rb.count }
func (rb *RingBuffer[T]) Cap() int { return rb.size }

func (rb *RingBuffer[T]) Peek() (T, error) {
	if rb.count == 0 {
		var zero T
		return zero, errors.New("buffer empty")
	}
	return rb.data[rb.head], nil
}

func main() {
	rb := NewRingBuffer[int](3)
	rb.Push(1)
	rb.Push(2)
	rb.Push(3)

	item, _ := rb.Pop()
