import "fmt"

type Trie struct {
	children map[byte]*Trie
	isEnd    bool
	value    string
}

func NewTrie() *Trie {
	return &Trie{children: make(map[byte]*Trie)}
}

func (t *Trie) Insert(word string) {
	node := t
	for i := 0; i < len(word); i++ {
		ch := word[i]
		if node.children[ch] == nil {
			node.children[ch] = NewTrie()
		}
		node = node.children[ch]
	}
	node.isEnd = true
	node.value = word
}

func (t *Trie) Search(word string) bool {
	node := t
	for i := 0; i < len(word); i++ {
		ch := word[i]
		if node.children[ch] == nil {
			return false
		}
		node = node.children[ch]
	}
	return node.isEnd
}

func (t *Trie) StartsWith(prefix string) []string {
	node := t
	for i := 0; i < len(prefix); i++ {
		ch := prefix[i]
		if node.children[ch] == nil {
			return nil
		}
		node = node.children[ch]
	}
	var result []string
	node.collect(&result)
	return result
}

func (t *Trie) collect(result *[]string) {
	if t.isEnd {
		*result = append(*result, t.value)
	}
	for _, child := range t.children {
		child.collect(result)
	}
}

func main() {
	trie := NewTrie()
	words := []string{"merhaba", "merak", "mercan", "merkez", "meral"}
	for _, w := range words {
		trie.Insert(w)
	}

	fmt.Println("Search 'merhaba':", trie.Search("merhaba"))
	fmt.Println("Search 'xyz':", trie.Search("xyz"))
	fmt.Println("Prefix 'mer':", trie.StartsWith("mer"))
	fmt.Println("Prefix 'merk':", trie.StartsWith("merk"))
}

