import (
	"fmt"
	"hash/fnv"
)

type BloomFilter struct {
	bits    []bool
	size    uint
	hashCount int
}

func NewBloomFilter(size uint, hashCount int) *BloomFilter {
	return &BloomFilter{
		bits:      make([]bool, size),
		size:      size,
		hashCount: hashCount,
	}
}

func (bf *BloomFilter) Add(item string) {
	for i := 0; i < bf.hashCount; i++ {
		hash := bf.hash(item, i)
		bf.bits[hash%bf.size] = true
	}
}

func (bf *BloomFilter) Contains(item string) bool {
	for i := 0; i < bf.hashCount; i++ {
		hash := bf.hash(item, i)
		if !bf.bits[hash%bf.size] {
			return false
		}
	}
	return true
}

func (bf *BloomFilter) hash(item string, seed int) uint {
	h := fnv.New64a()
	h.Write([]byte(item))
	h.Write([]byte{byte(seed)})
	return uint(h.Sum64())
}

func main() {
	bf := NewBloomFilter(1000, 3)

	urls := []string{
		"https://example.com",
		"https://google.com",
		"https://github.com",
	}

	for _, url := range urls {
		bf.Add(url)
	}

	testURLs := []string{
		"https://example.com",
		"https://unknown-site.com",
		"https://google.com",
	}

	for _, url := range testURLs {
		fmt.Printf("%s: %v (might be false positive)\n", url, bf.Contains(url))
	}
}

