import "fmt"

type Command interface {
	Execute() error
	Undo() error
}

type CreateFileCommand struct {
	filename string
	content  string
}

func (c *CreateFileCommand) Execute() error {
	fmt.Printf("Creating file: %s with content: %s\n", c.filename, c.content)
	return nil
}

func (c *CreateFileCommand) Undo() error {
	fmt.Printf("Deleting file: %s\n", c.filename)
	return nil
}

type UpdateConfigCommand struct {
	key   string
	value string
	oldValue string
}

func (c *UpdateConfigCommand) Execute() error {
	fmt.Printf("Setting config %s = %s\n", c.key, c.value)
	return nil
}

func (c *UpdateConfigCommand) Undo() error {
	fmt.Printf("Restoring config %s = %s\n", c.key, c.oldValue)
	return nil
}

type CommandQueue struct {
	commands    []Command
	history     []Command
}

func (cq *CommandQueue) Add(cmd Command) {
	cq.commands = append(cq.commands, cmd)
}

func (cq *CommandQueue) ExecuteAll() {
	for _, cmd := range cq.commands {
		if err := cmd.Execute(); err != nil {
			fmt.Println("Error:", err)
			return
		}
		cq.history = append(cq.history, cmd)
	}
	cq.commands = nil
}

func (cq *CommandQueue) UndoLast() {
	if len(cq.history) > 0 {
		cmd := cq.history[len(cq.history)-1]
		cq.history = cq.history[:len(cq.history)-1]
		cmd.Undo()
	}
}

func main() {
	queue := &CommandQueue{}

	queue.Add(&CreateFileCommand{filename: "test.txt", content: "hello"})
	queue.Add(&UpdateConfigCommand{key: "theme", value: "dark", oldValue: "light"})

	queue.ExecuteAll()
	queue.UndoLast()
}

