public class StructuredTimeout {
    public static void main(String[] args) throws Exception {
        Instant deadline = Instant.now().plusMillis(500);

        try (var scope = new StructuredTaskScope.ShutdownOnFailure()) {
            Future<String> task1 = scope.fork(() -> {
                Thread.sleep(1000);
                return "Slow result";
            });

            Future<String> task2 = scope.fork(() -> {
                Thread.sleep(100);
                return "Fast result";
            });

            try {
                scope.joinUntil(deadline);
                scope.throwIfFailed();
                System.out.println(task1.resultNow());
                System.out.println(task2.resultNow());
            } catch (Exception e) {
                System.out.println("Deadline exceeded or failed: " + e.getMessage());
            }
        }
    }
}

