        try (var scope = new StructuredTaskScope.ShutdownOnFailure()) {
            Future<String> success = scope.fork(() -> "Success");
            Future<String> failure = scope.fork(() -> {
                throw new RuntimeException("Task failed!");
            });

            try {
                scope.join();
                scope.throwIfFailed();
            } catch (Exception e) {
                System.out.println("Scope failed: " + e.getMessage());
                System.out.println("Success isDone: " + success.resultNow());
