            }
        }
    }
}

public class ScopedValueMultiLayer {
    private static final ScopedValue<String> USER = ScopedValue.newInstance();
    private static final ScopedValue<String> REQUEST_ID = ScopedValue.newInstance();

    static void handleRequest(String user, String requestId, Runnable action) {
        ScopedValue.where(USER, user)
            .where(REQUEST_ID, requestId)
            .run(() -> {
                System.out.println("Processing request for " + USER.get());
                action.run();
            });
    }

    public static void main(String[] args) {
        handleRequest("alice", "REQ-001", () -> {
            System.out.println("User: " + USER.get());
            System.out.println("Request: " + REQUEST_ID.get());
            nestedFunction();
        });
    }

    static void nestedFunction() {
        // ScopedValue otomatik olarak inherit edilir
        System.out.println("Nested - User: " + USER.get());
        System.out.println("Nested - Request: " + REQUEST_ID.get());
    }
}

