	if atomic.CompareAndSwapInt64(&value, old, newVal) {
		fmt.Println("Update succeeded:", atomic.LoadInt64(&value))
	} else {
		fmt.Println("Update failed, value changed")
	}

	// Basarisiz CAS denemesi
	if atomic.CompareAndSwapInt64(&value, 999, 0) {
		fmt.Println("Unexpected success")
	} else {
		fmt.Println("CAS correctly failed (expected 100, got 150)")
	}
}

