	"time"
)

var (
	ready bool
	cond  = sync.NewCond(&sync.Mutex{})
)

func worker(id int) {
	cond.L.Lock()
	for !ready {
		cond.Wait()
	}
	fmt.Printf("Worker %d starting\n", id)
	cond.L.Unlock()
}

func main() {
	for i := 1; i <= 5; i++ {
		go worker(i)
	}

	time.Sleep(100 * time.Millisecond)
	fmt.Println("All workers waiting...")

	cond.L.Lock()
	ready = true
	cond.Broadcast()
	cond.L.Unlock()

	time.Sleep(100 * time.Millisecond)
	fmt.Println("All workers started")
}

package main

import (
	"fmt"
	"math"
	"math/bits"
)

type HyperLogLog struct {
	registers []uint8
	m         uint
	b         uint
}

func NewHyperLogLog(b uint) *HyperLogLog {
	m := uint(1) << b
	return &HyperLogLog{
		registers: make([]uint8, m),
		m:         m,
		b:         b,
	}
}

func (hll *HyperLogLog) Add(item string) {
	hash := fnvHash(item)
	idx := hash >> (64 - hll.b)

	// Leading zeros + 1
	r := bits.LeadingZeros64(hash<<hll.b) + 1
	if r > 64 { r = 64 }

	if uint8(r) > hll.registers[idx] {
		hll.registers[idx] = uint8(r)
	}
}

func (hll *HyperLogLog) Count() uint64 {
	var sum float64
	for _, v := range hll.registers {
		sum += 1.0 / math.Pow(2, float64(v))
	}

	alpha := 0.7213 / (1.0 + 1.079/float64(hll.m))
	estimate := alpha * float64(hll.m*hll.m) / sum
	return uint64(estimate)
}

func fnvHash(item string) uint64 {
	var h uint64 = 14695981039346656037
	for _, c := range []byte(item) {
		h ^= uint64(c)
		h *= 1099511628211
	}
	return h
}

