}

public class ScopedValueTransaction {
    private static final ScopedValue<String> TX_ID = ScopedValue.newInstance();
    private static final ScopedValue<Boolean> TX_ACTIVE = ScopedValue.newInstance();

    static void inTransaction(String txId, Runnable action) {
        ScopedValue.where(TX_ID, txId)
            .where(TX_ACTIVE, true)
            .run(() -> {
                System.out.println("TX " + TX_ID.get() + " started");
                try {
                    action.run();
                    System.out.println("TX " + TX_ID.get() + " committed");
                } catch (Exception e) {
                    System.out.println("TX " + TX_ID.get() + " rolled back");
                }
            });
    }

    static void query(String sql) {
        if (TX_ACTIVE.get()) {
            System.out.println("Executing in TX " + TX_ID.get() + ": " + sql);
        } else {
            System.out.println("No active transaction: " + sql);
        }
    }

    public static void main(String[] args) {
        inTransaction("TX-001", () -> {
            query("SELECT * FROM users");
            query("UPDATE users SET name='Alice' WHERE id=1");
        });
    }
}

