import java.time.Instant;
import java.util.concurrent.Executors;
import java.util.concurrent.ThreadLocalRandom;

public class ThreadPoolComparison {
    static void simulateWork() {
        try {
            Thread.sleep(ThreadLocalRandom.current().nextInt(5, 20));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    public static void main(String[] args) throws InterruptedException {
        int taskCount = 10_000;

        // Platform threads
        var start = Instant.now();
        try (var executor = Executors.newFixedThreadPool(200)) {
            for (int i = 0; i < taskCount; i++) {
                executor.submit(ThreadPoolComparison::simulateWork);
            }
        }
        var platformTime = java.time.Duration.between(start, Instant.now()).toMillis();

        // Virtual threads
        start = Instant.now();
        try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int i = 0; i < taskCount; i++) {
                executor.submit(ThreadPoolComparison::simulateWork);
            }
        }
        var virtualTime = java.time.Duration.between(start, Instant.now()).toMillis();

        System.out.println("Platform threads: " + platformTime + "ms");
        System.out.println("Virtual threads: " + virtualTime + "ms");
    }
}

