import (
	"fmt"
	"sync"
	"time"
)

type BoundedBuffer struct {
	buf  []int
	size int
	cond *sync.Cond
}

func NewBoundedBuffer(size int) *BoundedBuffer {
	return &BoundedBuffer{
		buf:  make([]int, 0, size),
		size: size,
		cond: sync.NewCond(&sync.Mutex{}),
	}
}

func (bb *BoundedBuffer) Put(item int) {
	bb.cond.L.Lock()
	defer bb.cond.L.Unlock()

	for len(bb.buf) >= bb.size {
		bb.cond.Wait()
	}
	bb.buf = append(bb.buf, item)
	bb.cond.Signal()
}

func (bb *BoundedBuffer) Get() int {
	bb.cond.L.Lock()
	defer bb.cond.L.Unlock()

	for len(bb.buf) == 0 {
		bb.cond.Wait()
	}
	item := bb.buf[0]
	bb.buf = bb.buf[1:]
	bb.cond.Signal()
	return item
}

func main() {
	bb := NewBoundedBuffer(3)

	go func() {
		for i := 1; i <= 10; i++ {
			bb.Put(i)
			fmt.Printf("Put: %d\n", i)
		}
	}()

	go func() {
		for i := 1; i <= 10; i++ {
			item := bb.Get()
			fmt.Printf("Get: %d\n", item)
			time.Sleep(50 * time.Millisecond)
		}
	}()

	time.Sleep(2 * time.Second)
}

