import java.util.List;

public class ComplexInstanceof {
    sealed interface Result permits Data, Error, Loading {}
    record Data(List<String> items, int total) implements Result {}
    record Error(String message, int code) implements Result {}
    record Loading(float progress) implements Result {}

    static String processResult(Result result) {
        if (result instanceof Data(var items, var total) && !items.isEmpty()) {
            return "Data: " + items.size() + " of " + total;
        }
        if (result instanceof Error(var msg, var code) && code >= 500) {
            return "Server error: " + msg;
        }
        if (result instanceof Loading(var p)) {
            return "Loading: " + (int)(p * 100) + "%";
        }
        return "Unknown state";
    }

    public static void main(String[] args) {
        System.out.println(processResult(new Data(List.of("a", "b"), 10)));
        System.out.println(processResult(new Error("Not found", 404)));
        System.out.println(processResult(new Loading(0.5f)));
    }
}

public record Email(String address) {
    private static final String EMAIL_REGEX = "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$";

    public Email {
        if (address == null || address.isBlank()) {
            throw new IllegalArgumentException("Email cannot be blank");
        }
        if (!address.matches(EMAIL_REGEX)) {
            throw new IllegalArgumentException("Invalid email format: " + address);
        }
        address = address.toLowerCase();
    }

    public String domain() {
        return address.substring(address.indexOf('@') + 1);
    }

    public String localPart() {
        return address.substring(0, address.indexOf('@'));
    }

    public static void main(String[] args) {
        var email = new Email("Alice@Example.COM");
        System.out.println("Address: " + email.address());
        System.out.println("Domain: " + email.domain());
        System.out.println("Local part: " + email.localPart());

        try {
            new Email("invalid");
        } catch (IllegalArgumentException e) {
            System.out.println("Validation: " + e.getMessage());
        }
    }
}

