public class MemoryMismatch {
    public static void main(String[] args) {
        try (Arena arena = Arena.ofConfined()) {
            MemorySegment seg1 = arena.allocate(16);
            MemorySegment seg2 = arena.allocate(16);

            seg1.copyFrom(MemorySegment.ofArray(new byte[]{1, 2, 3, 4}));
            seg2.copyFrom(MemorySegment.ofArray(new byte[]{1, 2, 5, 4}));

            long mismatchIndex = seg1.mismatch(seg2);
            System.out.println("First mismatch at: " + mismatchIndex);

            if (mismatchIndex != -1) {
                byte b1 = seg1.get(ValueLayout.JAVA_BYTE, mismatchIndex);
                byte b2 = seg2.get(ValueLayout.JAVA_BYTE, mismatchIndex);
                System.out.println("seg1: " + b1 + ", seg2: " + b2);
            }

            // Ayni bellek
            MemorySegment seg3 = arena.allocate(8);
            seg3.copyFrom(MemorySegment.ofArray(new byte[]{1, 2, 3, 4}));
            MemorySegment seg4 = arena.allocate(8);
            seg4.copyFrom(seg3);
            System.out.println("Same? " + (seg3.mismatch(seg4) == -1));
        }
    }
}

