public record QueryBuilder(
    String select,
    String from,
    String where,
    String orderBy,
    Integer limit,
    Integer offset
) {
    public static class Builder {
        private String select = "*";
        private String from;
        private String where;
        private String orderBy;
        private Integer limit;
        private Integer offset;

        public Builder from(String table) {
            this.from = table;
            return this;
        }

        public Builder select(String columns) {
            this.select = columns;
            return this;
        }

        public Builder where(String condition) {
            this.where = condition;
            return this;
        }

        public Builder orderBy(String order) {
            this.orderBy = order;
            return this;
        }

        public Builder limit(int limit) {
            this.limit = limit;
            return this;
        }

        public Builder offset(int offset) {
            this.offset = offset;
            return this;
        }

        public QueryBuilder build() {
            if (from == null) throw new IllegalStateException("FROM is required");
            return new QueryBuilder(select, from, where, orderBy, limit, offset);
        }
    }

    public String toSql() {
        var sql = "SELECT " + select + " FROM " + from;
        if (where != null) sql += " WHERE " + where;
        if (orderBy != null) sql += " ORDER BY " + orderBy;
        if (limit != null) sql += " LIMIT " + limit;
        if (offset != null) sql += " OFFSET " + offset;
        return sql;
    }

    public static void main(String[] args) {
        var query = new QueryBuilder.Builder()
            .select("id, name, email")
            .from("users")
            .where("active = true")
            .orderBy("name ASC")
            .limit(10)
            .offset(20)
            .build();

        System.out.println(query.toSql());
    }
}

import java.lang.invoke.MethodHandles;
import java.lang.invoke.VarHandle;
import java.util.concurrent.atomic.AtomicInteger;

public class VarHandleCounter {
    private volatile int count;
    private static final VarHandle COUNT;

    static {
        try {
            COUNT = MethodHandles.lookup()
                .findVarHandle(VarHandleCounter.class, "count", int.class);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    public int increment() {
        return (int) COUNT.getAndAdd(this, 1);
    }

    public int decrement() {
        return (int) COUNT.getAndAdd(this, -1);
    }

    public int get() {
        return (int) COUNT.getVolatile(this);
    }

    public static void main(String[] args) throws InterruptedException {
        var counter = new VarHandleCounter();
        var threads = new Thread[100];

        for (int i = 0; i < threads.length; i++) {
            threads[i] = new Thread(() -> {
                for (int j = 0; j < 1000; j++) {
                    counter.increment();
                }
            });
            threads[i].start();
        }

        for (var t : threads) {
            t.join();
        }

        System.out.println("Expected: 100000, Got: " + counter.get());
    }
}

