public sealed interface PaymentMethod 
    permits CreditCard, BankTransfer, CryptoWallet, GiftCard {}

record CreditCard(String lastFour, String expiry) implements PaymentMethod {}
record BankTransfer(String iban, String bankName) implements PaymentMethod {}
record CryptoWallet(String address, String currency) implements PaymentMethod {}
record GiftCard(String code, double balance) implements PaymentMethod {}

class PaymentProcessor {
    static String process(PaymentMethod method, double amount) {
        return switch (method) {
            case CreditCard(var last, _) -> 
                "Charged " + amount + " to card ending in " + last;
            case BankTransfer(var iban, _) -> 
                "Transferred " + amount + " to IBAN " + iban;
            case CryptoWallet(var addr, var cur) -> 
                "Sent " + amount + " " + cur + " to " + addr;
            case GiftCard(var code, var bal) -> {
                if (bal < amount) yield "Insufficient gift card balance";
                yield "Applied " + amount + " from gift card " + code;
            }
        };
