func readFile(filename string) <-chan string {
	out := make(chan string)
	go func() {
		defer close(out)
		f, err := os.Open(filename)
		if err != nil {
			fmt.Println("Error:", err)
			return
		}
		defer f.Close()
		scanner := bufio.NewScanner(f)
		for scanner.Scan() {
			out <- scanner.Text()
		}
	}()
	return out
}

func transform(in <-chan string) <-chan string {
	out := make(chan string)
	go func() {
		defer close(out)
		for line := range in {
			out <- strings.ToUpper(line)
		}
	}()
	return out
}

func writeFile(in <-chan string, filename string) {
	f, err := os.Create(filename)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	defer f.Close()

	for line := range in {
		fmt.Fprintln(f, line)
	}
}

