type RateLimiter struct {
	tokens chan struct{}
	close  chan struct{}
}

func NewRateLimiter(rate int, per time.Duration) *RateLimiter {
	rl := &RateLimiter{
		tokens: make(chan struct{}, rate),
		close:  make(chan struct{}),
	}

	// Baslangicta tokenlari doldur
	for i := 0; i < rate; i++ {
		rl.tokens <- struct{}{}
	}

	// Periyodik token ekleme
	go func() {
		ticker := time.NewTicker(per / time.Duration(rate))
		defer ticker.Stop()
		for {
			select {
			case <-ticker.C:
				select {
				case rl.tokens <- struct{}{}:
				default:
				}
			case <-rl.close:
				return
			}
		}
	}()

	return rl
}

func (rl *RateLimiter) Wait() {
	<-rl.tokens
}

func (rl *RateLimiter) Stop() {
	close(rl.close)
}

func main() {
	limiter := NewRateLimiter(2, time.Second)
	defer limiter.Stop()

	for i := 1; i <= 10; i++ {
		limiter.Wait()
		fmt.Printf("Request %d at %s\n", i, time.Now().Format("15:04:05.000"))
	}
}

