type Curry<P extends unknown[], R> = 
  P extends [infer F, ...infer Rest]
    ? Rest extends []
      ? (arg: F) => R
      : (arg: F) => Curry<Rest, R>
    : () => R;

function curry<P extends unknown[], R>(
  fn: (...args: P) => R
): Curry<P, R> {
  return function curried(...args: unknown[]): unknown {
    if (args.length >= fn.length) {
      return fn(...args as P);
    }
    return (...next: unknown[]) => curried(...args, ...next);
  } as Curry<P, R>;
}

