class HttpError extends Error {
  constructor(status, message, options) {
    super('HTTP ' + status + ': ' + message, options);
    this.name = 'HttpError';
    this.status = status;
  }
}

class RateLimitError extends Error {
  constructor(retryAfter, options) {
    super('Rate limited. Retry after ' + retryAfter + 's', options);
    this.name = 'RateLimitError';
    this.retryAfter = retryAfter;
  }
}

async function fetchWithErrorMapping(url) {
  try {
    const response = await fetch(url);
    if (response.status === 429) {
      const retryAfter = response.headers.get('Retry-After');
      throw new RateLimitError(parseInt(retryAfter) || 60);
    }
    if (!response.ok) {
      throw new HttpError(response.status, response.statusText);
    }
    return response.json();
  } catch (err) {
    if (err instanceof HttpError || err instanceof RateLimitError) throw err;
    throw new Error('Network error', { cause: err });
  }
}

