class StepProcessor {
  constructor() {
    this.steps = [];
  }
  addStep(name, handler) {
    this.steps.push({ name, handler });
    return this;
  }
  execute(data) {
    let currentData = data;
    const runStep = (index) => {
      if (index >= this.steps.length) {
        return Promise.resolve(currentData);
      }
      const { name, handler } = this.steps[index];
      const { promise, resolve, reject } = Promise.withResolvers();
      try {
        const result = handler(currentData, (err, newData) => {
          if (err) reject(err);
          else resolve(newData);
        });
        if (result instanceof Promise) {
          result.then(resolve).catch(reject);
        } else if (result !== undefined) {
          resolve(result);
        }
      } catch (err) {
        reject(err);
      }
      return promise.then(newData => {
        currentData = newData;
        return runStep(index + 1);
      });
    };
    return runStep(0);
  }
}

const processor = new StepProcessor()
  .addStep('Validate', (data) => {
    if (!data) throw new Error('Data required');
    return data;
  })
  .addStep('Transform', (data) => {
    return { ...data, processed: true };
  });

processor.execute({ name: 'test' })
  .then(result => console.log('Result:', result))
