import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class VirtualConnectionManager {
    private final AtomicInteger activeConnections = new AtomicInteger();
    void handleConnection(int id) {
        activeConnections.incrementAndGet();
        try {
            System.out.println('Connection ' + id + ' started (active: ' + activeConnections.get() + ')');
            Thread.sleep(ThreadLocalRandom.current().nextInt(10, 100));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        } finally {
            activeConnections.decrementAndGet();
        }
    }
    public static void main(String[] args) throws InterruptedException {
        var manager = new VirtualConnectionManager();
        try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int i = 0; i < 1000; i++) {
                int id = i;
                executor.submit(() -> manager.handleConnection(id));
            }
        }
        System.out.println('All connections handled');
    }
}

