        switch (event) {
            case UserCreated(var id, var email) -> 
                System.out.println('User ' + id + ' created with email ' + email);
            case UserUpdated(var id, var field, _, _) -> 
                System.out.println('User ' + id + ' updated field: ' + field);
            case UserDeleted(var id, var reason) -> 
                System.out.println('User ' + id + ' deleted: ' + reason);
        }
    }

    public static void main(String[] args) {
        handle(new UserCreated('user-1', 'alice@test.com'));
        handle(new UserUpdated('user-1', 'email', 'old', 'new'));
        handle(new UserDeleted('user-1', 'inactive'));
    }
}

