public sealed class Shape permits Circle, Square {}
final class Circle extends Shape {
    double radius;
    Circle(double r) { radius = r; }
}
final class Square extends Shape {
    double side;
    Square(double s) { side = s; }
}

class AreaCalc {
    static double area(Shape s) {
        return switch (s) {
            case Circle c -> Math.PI * c.radius * c.radius;
            case Square sq -> sq.side * sq.side;
        };
    }

    public static void main(String[] args) {
        System.out.println(area(new Circle(5)));
        System.out.println(area(new Square(4)));
    }
}

public class InstanceofMatch {
    public static void main(String[] args) {
        Object obj = 'Hello World';

        if (obj instanceof String s && s.length() > 5) {
            System.out.println('Long string: ' + s.toUpperCase());
        }

        Object num = 42;
        if (num instanceof Integer i) {
            System.out.println('Integer: ' + (i + 1));
        }
    }
}

