}

func main() {
	var config atomic.Value
	config.Store(&Config{Host: "localhost", Port: 8080})

	cfg := config.Load().(*Config)
	fmt.Printf("Config: %s:%d\n", cfg.Host, cfg.Port)

	config.Store(&Config{Host: "example.com", Port: 443})
